import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import gsap from "gsap";
import axios from "axios";
import FormPage from "./FormPage";  // import the component where you want to pass the response

const Login = () => {
  // States
  const [username, setUsername] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState(null);
  const [response, setResponse] = useState(null);  // Response state to hold the API data
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const navigate = useNavigate();

  // Handle form submission
  const handleSubmit = async (e) => {
    e.preventDefault(); // Prevent the default form submission

    try {
      const options = {
        method: "get",
        url: "http://bidwheels-api-env.eba-ts5rcstj.us-east-1.elasticbeanstalk.com/login",
        params: { username, password },
        headers: {
          "Cache-Control": "no-cache",
          Accept: "*/*",
          "User-Agent": "Fetch Client",
          "Accept-Encoding": "gzip, deflate",
          Connection: "keep-alive",
        },
      };

      const response = await axios.request(options);
      setResponse(response.data);  // Store the response data
      console.log(response.data);
      setIsLoggedIn(true);  // Set the login status to true
    } catch (error) {
      setError("Username or password is incorrect.");
      console.log("--->", error);
    }
  };

  // After successful login, navigate to form page
  useEffect(() => {
    if (isLoggedIn) {
      navigate("/formpage");
    }
  }, [isLoggedIn, navigate]);

  return (
    <>
      <div className="login-container">
        <div className="login-left">
          <div className="logo">TRUXGO</div>
        </div>
        <div className="login-right">
          <div className="login-form">
            <h2>Log In to your account</h2>
            <form onSubmit={handleSubmit}>
              <label>Email</label>
              <input
                type="email"
                placeholder="Enter your email"
                value={username}
                onChange={(e) => setUsername(e.target.value)}
                required
              />
              <label>Password</label>
              <input
                type="password"
                placeholder="Enter your password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                required
              />
              <a href="/forgot-password" className="forgot-password">
                Forgot your password?
              </a>
              {error && (
                <div style={{ color: "red" }}>
                  <p>{error}</p>
                </div>
              )}
              <button type="submit">Log In</button>
            </form>
          </div>
        </div>
      </div>

      {/* Pass the response as a prop to FormPage */}
      {isLoggedIn && <FormPage response={response} />}
    </>
  );
};

export default Login;
